() => {
  const toggles = document.querySelectorAll('.col-toggle-item');
  const result = [];
  toggles.forEach(item => {
    const label = item.querySelector('.col-toggle-label').textContent.trim();
    const checkbox = item.querySelector('input[type="checkbox"]');
    const isChecked = checkbox.checked;
    const isDisabled = checkbox.disabled;
    const colId = checkbox.dataset.colId;
    const hasLock = item.querySelector('.col-lock-icon') !== null;
    const isRequired = item.classList.contains('required');
    result.push({ label, colId, isChecked, isDisabled, hasLock, isRequired });
  });
  return result;
}

