async (page) => {
  // Intercept the tier API to return a Free-tier response
  await page.route('**/api/auth/tier', route => {
    route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        tier: 'free',
        features: {
          sentiment_filter: false,
          ai_ticker_recommendations: false,
          deduplication: false,
          max_items: 50
        }
      })
    });
  });

  // Clear localStorage so we get a fresh state
  await page.evaluate(() => localStorage.removeItem('instnews_column_visibility'));

  // Reload page to apply the intercepted tier
  await page.goto('http://localhost:8000/terminal');
  await page.waitForLoadState('networkidle');

  // Hide auth/upgrade overlays
  await page.evaluate(() => {
    const authGate = document.getElementById('auth-gate');
    const upgradeGate = document.getElementById('upgrade-gate');
    if (authGate) authGate.style.display = 'none';
    if (upgradeGate) upgradeGate.style.display = 'none';
  });

  // Wait a moment for tier to load
  await page.waitForTimeout(1000);

  // Open column settings panel
  await page.evaluate(() => document.getElementById('btn-col-settings').click());

  // Check all column toggle states
  const columnStates = await page.evaluate(() => {
    const toggles = document.querySelectorAll('.col-toggle-item');
    return Array.from(toggles).map(item => {
      const label = item.querySelector('.col-toggle-label').textContent.trim();
      const checkbox = item.querySelector('input[type="checkbox"]');
      const hasLock = item.querySelector('.col-lock-icon') !== null;
      const isLocked = item.classList.contains('locked');
      return {
        label,
        colId: checkbox.dataset.colId,
        checked: checkbox.checked,
        disabled: checkbox.disabled,
        hasLock,
        isLocked
      };
    });
  });

  return columnStates;
}

