  // Check if the tier route was actually hit
  const requests = [];
  page.on('request', req => {
    if (req.url().includes('auth/tier')) {
      requests.push(req.url());
    }
  });

  // Check current state of userTier/userFeatures by looking for them in the DOM or evaluating
  const state = await page.evaluate(() => {
    // Try to find any indication of tier state
    // Check if there are any elements with lock class
    const lockIcons = document.querySelectorAll('.col-lock-icon');
    const lockedItems = document.querySelectorAll('.col-toggle-item.locked');

    // Check if the fetchTier has been called by looking at network
    return {
      lockIconCount: lockIcons.length,
      lockedItemCount: lockedItems.length,
      // Check the column settings panel HTML for lock-related classes
      panelHTML: document.getElementById('column-settings-panel')?.innerHTML.substring(0, 500)
    };
  });

  return state;
}

